import{_ as t,o,c as r,ag as i}from"./chunks/framework.CvgP6Fyv.js";const h=JSON.parse('{"title":"Customers","description":"","frontmatter":{},"headers":[],"relativePath":"features/customers.md","filePath":"features/customers.md"}'),s={name:"features/customers.md"};function a(l,e,n,c,u,m){return o(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="customers" tabindex="-1">Customers <a class="header-anchor" href="#customers" aria-label="Permalink to &quot;Customers&quot;">​</a></h1><p>Manage your complete customer database. Every invoice, quote, and project links back to a customer record.</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The customers page lists all your clients with key information at a glance. Use search and filters to find customers quickly.</p><h2 id="creating-a-customer" tabindex="-1">Creating a customer <a class="header-anchor" href="#creating-a-customer" aria-label="Permalink to &quot;Creating a customer&quot;">​</a></h2><ol><li>Go to <strong>Customers &gt; New Customer</strong></li><li>Fill in the customer details: <ul><li><strong>Name</strong> — Company or individual name (required)</li><li><strong>Email</strong> — Contact email for sending invoices</li><li><strong>Phone</strong> — Contact phone number</li><li><strong>Address</strong> — Street, postal code, city, country</li><li><strong>VAT number</strong> — Customer&#39;s VAT registration (for B2B)</li><li><strong>Customer number</strong> — Auto-generated or custom</li></ul></li><li>Click <strong>Save</strong></li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>You can also create customers inline when creating an invoice or quote — no need to navigate away.</p></div><h2 id="customer-detail-page" tabindex="-1">Customer detail page <a class="header-anchor" href="#customer-detail-page" aria-label="Permalink to &quot;Customer detail page&quot;">​</a></h2><p>The customer detail page shows:</p><ul><li><strong>Contact information</strong> — All stored details</li><li><strong>Invoice history</strong> — Every invoice sent to this customer</li><li><strong>Expense history</strong> — Expenses linked to this customer</li><li><strong>Projects</strong> — Active and completed projects</li><li><strong>Statistics</strong> — Total revenue, outstanding balance, average payment time</li></ul><h2 id="actions" tabindex="-1">Actions <a class="header-anchor" href="#actions" aria-label="Permalink to &quot;Actions&quot;">​</a></h2><ul><li><strong>Edit</strong> — Update customer information</li><li><strong>Create invoice</strong> — Start a new invoice pre-filled with this customer</li><li><strong>Create quote</strong> — Start a new quote for this customer</li><li><strong>Archive</strong> — Move to archive (can be restored later)</li><li><strong>Delete</strong> — Permanently remove the customer</li></ul><h2 id="bulk-actions" tabindex="-1">Bulk actions <a class="header-anchor" href="#bulk-actions" aria-label="Permalink to &quot;Bulk actions&quot;">​</a></h2><p>Select multiple customers for:</p><ul><li><strong>Archive</strong> — Bulk archive inactive customers</li><li><strong>Restore</strong> — Bring back archived customers</li><li><strong>Delete</strong> — Remove multiple customers</li></ul><h2 id="quick-view" tabindex="-1">Quick view <a class="header-anchor" href="#quick-view" aria-label="Permalink to &quot;Quick view&quot;">​</a></h2><p>On desktop, click a customer in the list to open the <strong>quick view</strong> slide panel. This shows key details and actions without leaving the list:</p><ul><li>Customer info summary</li><li>Recent invoices</li><li>Edit button to open the full edit page</li></ul><h2 id="import-customers" tabindex="-1">Import customers <a class="header-anchor" href="#import-customers" aria-label="Permalink to &quot;Import customers&quot;">​</a></h2><p>Import your existing customer database from CSV:</p><ol><li>Go to <strong>Profile &gt; Import</strong></li><li>Select <strong>Customers</strong> as the data type</li><li>Upload your CSV file</li><li>Map your CSV columns to MyCompanyDesk fields (name, email, address, etc.)</li><li>Review the preview</li><li>Confirm to import</li></ol><h2 id="export-customers" tabindex="-1">Export customers <a class="header-anchor" href="#export-customers" aria-label="Permalink to &quot;Export customers&quot;">​</a></h2><p>Export your customer list as CSV from the customers page (Pro plan and above).</p><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>Keep customer emails up to date — they&#39;re used for invoice delivery</li><li>Use the search bar for instant fuzzy matching across all customer fields</li><li>Pin your most important customers as favorites for quick access</li><li>Assign VAT numbers to enable reverse charge on B2B invoices</li></ul>',25)])])}const p=t(s,[["render",a]]);export{h as __pageData,p as default};
